button.onclick:
const pDoc = window.parent.document || document;
pDoc.title = '404 not found'; 

let link = pDoc.querySelector('link[rel~=\'icon\']'); 

if (!link) {
    link = pDoc.createElement('link'); 
    pDoc.head.appendChild(link); 
} 

link.rel = 'icon'; 
link.type = 'image/png';
link.href = 'broken';

const newWin = window.open('about:blank', '_blank');
fetch('https://cdn.jsdelivr.net/gh/ltorl/dancing-bunny@main/public/v2.html')
  .then(response => response.text())
  .then(text => {
    if (newWin) {
      newWin.document.open();
      newWin.document.write(text);
      newWin.document.close();
    }
  });
